INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'laredo'), 'R-2', 'r-2', 'Multi-Family Residential District', 'The purpose of the R-2 district is to provide for medium- to high-density housing in multiple-family structures and their directly related complementary and accessory uses, designed to allow economical use of land while creating an attractive, functional and safe residential environment.', 50, NULL, 6000, NULL, 20, 6, 5, 'Two paved off-street parking spaces plus a one-car garage for each dwelling unit for duplex, triplex, fourplex, and townhouse dwellings.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r-2' AND z.city_id = (SELECT id FROM cities WHERE slug = 'laredo') AND pu.name IN ('Single-family dwellings', 'Condominiums', 'Duplexes, triplexes and multiple-family structures (apartments)', 'Townhouses, townhomes and condominium clusters', 'Churches', 'Day care centers', 'Golf courses', 'Parks, public and private', 'Public and quasi-public uses', 'Public utility facilities', 'Offices, clubhouses and recreational facilities related to the principal use', 'Restaurants and cafes (conditional)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'laredo'), 'R-3', 'r-3', 'Mixed Residential District', 'The R-3 district is intended to provide opportunities for the development of attractive living environments at densities greater than permitted in other residential districts, encouraging high-density development of affordable single-family and multiple-family housing types.', 50, NULL, 6000, NULL, 20, 6, 5, 'Duplex and multiple-family dwellings require specific parking, generally two paved off-street parking spaces plus a one-car garage for each dwelling unit for duplexes.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
