INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'm-1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'laredo') AND pu.name IN ('Light manufacturing', 'Warehousing', 'Industrial uses', 'Nationalization/"nacionalizacion" of vehicles enterprise (with SUP)', 'Bars, night clubs, cantinas, saloons, billiard parlors, and carnivals (prohibited within 300 feet of any residential district)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'laredo'), 'AE', 'ae', 'Arts And Entertainment District', 'The purpose of the AE District is to provide a mixed-use environment where arts and entertainment venues, commercial, residential and office uses harmoniously co-exist in a higher density, pedestrian-oriented environment.', NULL, NULL, 6000, NULL, 25, 10, 10, 'Exempt from off-street parking requirements.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'ae' AND z.city_id = (SELECT id FROM cities WHERE slug = 'laredo') AND pu.name IN ('Arts and entertainment venues', 'Commercial uses', 'Residential uses', 'Office uses', 'Duplex (Horizontal)') ON CONFLICT DO NOTHING;
